define i16 @mul_nsw_reassoc_prop(i16 %x) {
  %a = mul nsw i16 %x, 3
  %b = mul nsw i16 %a, 2
  ret i16 %b
}

define i16 @mul_nsw_reassoc_prop_neg(i16 %x) {
  %a = mul nsw i16 %x, -71
  %b = mul nsw i16 %a, 31
  ret i16 %b
}

define i16 @mul_nsw_reassoc_prop_no_nsw1(i16 %x) {
  %a = mul i16 %x, 3
  %b = mul nsw i16 %a, 2
  ret i16 %b
}

define i16 @mul_nsw_reassoc_prop_no_nsw2(i16 %x) {
  %a = mul nsw i16 %x, 3
  %b = mul i16 %a, 2
  ret i16 %b
}

define i16 @mul_nsw_reassoc_prop_overflow(i16 %x) {
  %a = mul nsw i16 %x, 1023
  %b = mul nsw i16 %a, 33
  ret i16 %b
}

define i8 @neg_nsw_mul_missing_nsw_on_mul(i8 %a1, i8 %a2, i8 %b) {
  %a = sub nsw i8 %a1, %a2
  %shl = mul i8 %a, %b
  %neg = sub nsw i8 0, %shl
  ret i8 %neg
}
